import { useState, useRef } from 'react';
import { useMutation, useQueryClient } from '@tanstack/react-query';
import { Upload, X, FileText, Loader2, CheckCircle2, AlertCircle } from 'lucide-react';
import { supabase } from '@/shared/lib/supabase';
import { useToast } from '@/hooks/use-toast';
// We will use a fixed overlay/modal approach instead of shadcn Dialog to remove dependencies
import { useEffect } from 'react';

interface TariffUploadDialogProps {
    companyId: string;
    onUploadSuccess?: () => void;
}

interface UploadState {
    file: File;
    progress: number;
    status: 'pending' | 'uploading' | 'processing' | 'completed' | 'error';
    error?: string;
}

export function TariffUploadDialog({ companyId, onUploadSuccess }: TariffUploadDialogProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [uploads, setUploads] = useState<UploadState[]>([]);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const { toast } = useToast();
    const queryClient = useQueryClient();

    // Mutation to create a batch
    const createBatchMutation = useMutation({
        mutationFn: async () => {
            const { data, error } = await supabase
                .from('tariff_batches')
                .insert({
                    company_id: companyId,
                    uploaded_by: (await supabase.auth.getUser()).data.user?.id,
                    status: 'processing',
                    file_count: uploads.length
                })
                .select()
                .single();

            if (error) throw error;
            return data;
        }
    });

    const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            const newFiles = Array.from(e.target.files).map(file => ({
                file,
                progress: 0,
                status: 'pending' as const
            }));
            setUploads(prev => [...prev, ...newFiles]);
        }
        // Reset input
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const removeFile = (index: number) => {
        setUploads(prev => prev.filter((_, i) => i !== index));
    };

    const startUpload = async () => {
        if (uploads.length === 0) return;

        try {
            // 1. Create Batch
            const batch = await createBatchMutation.mutateAsync();

            // 2. Upload files and create records
            const uploadPromises = uploads.map(async (uploadState, index) => {
                try {
                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'uploading', progress: 0 } : u));

                    const fileExt = uploadState.file.name.split('.').pop();
                    const fileName = `${companyId}/${batch.id}/${crypto.randomUUID()}.${fileExt}`;

                    // Upload to Storage
                    const { error: uploadError } = await supabase.storage
                        .from('tariff-pdfs')
                        .upload(fileName, uploadState.file);

                    if (uploadError) throw uploadError;

                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, progress: 50 } : u));

                    // Create DB record
                    const { data: fileRecord, error: dbError } = await supabase
                        .from('tariff_files')
                        .insert({
                            company_id: companyId,
                            batch_id: batch.id,
                            filename: uploadState.file.name,
                            storage_path: fileName,
                            file_size_bytes: uploadState.file.size,
                            mime_type: uploadState.file.type,
                            extraction_status: 'pending'
                        })
                        .select()
                        .single();

                    if (dbError) throw dbError;

                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'processing', progress: 75 } : u));

                    // Trigger Edge Function
                    const { data: extractedDataResponse, error: funcError } = await supabase.functions.invoke('process-tariff-sheet', {
                        body: {
                            company_id: companyId,
                            file_path: fileName,
                            file_id: fileRecord.id, // Pass ID to update status on completion
                            batch_id: batch.id
                        }
                    });

                    if (funcError) {
                        console.error("Edge function error:", funcError);
                        // Don't fail the whole upload if just the OCR fails, but mark it
                        setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'error', error: 'AI Processing Failed', progress: 100 } : u));
                    } else {
                        // Handle potential array response (even if edge function returns single object, we wrap it, but it should return array now)
                        const extractedDataArray = Array.isArray(extractedDataResponse) ? extractedDataResponse : [extractedDataResponse];

                        try {
                            for (const extractedData of extractedDataArray) {
                                // Create Tariff Version from Extracted Data
                                const { data: tariffVersion, error: tvError } = await supabase
                                    .from('tariff_versions')
                                    .insert({
                                        company_id: companyId,
                                        batch_id: batch.id,
                                        file_id: fileRecord.id,
                                        supplier_name: extractedData.supplier_name || 'Desconocida',
                                        tariff_name: extractedData.tariff_name || 'Tarifa Importada',
                                        tariff_type: extractedData.tariff_type || '2.0TD',
                                        valid_from: extractedData.valid_from || new Date().toISOString(),
                                        valid_to: extractedData.valid_to || null,
                                        is_active: true
                                    })
                                    .select()
                                    .single();

                                if (tvError) throw tvError;

                                const components = [];

                                // Energy Prices
                                for (let p = 1; p <= 6; p++) {
                                    const val = extractedData[`energy_p${p}`];
                                    if (val !== null && val !== undefined) {
                                        components.push({
                                            company_id: companyId,
                                            tariff_version_id: tariffVersion.id,
                                            component_type: 'energy_price',
                                            period: `P${p}`,
                                            price_eur_kwh: Number(val)
                                        });
                                    }
                                }

                                // Power Prices
                                for (let p = 1; p <= 6; p++) {
                                    const val = extractedData[`power_p${p}`];
                                    if (val !== null && val !== undefined) {
                                        components.push({
                                            company_id: companyId,
                                            tariff_version_id: tariffVersion.id,
                                            component_type: 'power_price',
                                            period: `P${p}`,
                                            price_eur_kw_year: Number(val)
                                        });
                                    }
                                }

                                // Fixed Fee
                                if (extractedData.fixed_fee !== null && extractedData.fixed_fee !== undefined) {
                                    components.push({
                                        company_id: companyId,
                                        tariff_version_id: tariffVersion.id,
                                        component_type: 'fixed_fee',
                                        fixed_price_eur_month: Number(extractedData.fixed_fee)
                                    });
                                }

                                if (components.length > 0) {
                                    const { error: cError } = await supabase
                                        .from('tariff_components')
                                        .insert(components);

                                    if (cError) throw cError;
                                }
                            }

                            setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'completed', progress: 100 } : u));

                        } catch (creationError: any) {
                            console.error("Error creating tariff from data:", creationError);
                            setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'error', error: 'Import Failed', progress: 100 } : u));
                        }
                    }
                } catch (err: any) {
                    console.error("Upload failed for file:", uploadState.file.name, err);
                    setUploads(prev => prev.map((u, i) => i === index ? { ...u, status: 'error', error: err.message } : u));
                }
            });

            await Promise.all(uploadPromises);

            toast({
                title: "Upload Complete",
                description: `Processed ${uploads.length} files.`,
            });

            onUploadSuccess?.();
            setIsOpen(false);
            setUploads([]);
            queryClient.invalidateQueries({ queryKey: ['tariff-batches'] });
            queryClient.invalidateQueries({ queryKey: ['tariff-versions'] });

        } catch (err: any) {
            toast({
                variant: "destructive",
                title: "Error creating batch",
                description: err.message
            });
        }
    };

    const isUploading = createBatchMutation.isPending || uploads.some(u => u.status === 'uploading' || u.status === 'processing');

    // Escape key to close
    useEffect(() => {
        const handleEsc = (e: KeyboardEvent) => {
            if (e.key === 'Escape' && !isUploading) setIsOpen(false);
        };
        window.addEventListener('keydown', handleEsc);
        return () => window.removeEventListener('keydown', handleEsc);
    }, [isUploading]);

    return (
        <>
            <button
                onClick={() => setIsOpen(true)}
                style={{
                    display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                    borderRadius: '0.375rem', fontSize: '0.875rem', fontWeight: 500,
                    padding: '0.5rem 1rem', backgroundColor: '#111827', color: 'white',
                    border: 'none', cursor: 'pointer'
                }}
            >
                <Upload size={16} style={{ marginRight: '0.5rem' }} />
                Subir Tarifas
            </button>

            {isOpen && (
                <div style={{
                    position: 'fixed', inset: 0, zIndex: 50, backgroundColor: 'rgba(0, 0, 0, 0.5)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '1rem'
                }}>
                    <div style={{
                        backgroundColor: 'white', borderRadius: '0.5rem', width: '100%', maxWidth: '500px',
                        boxShadow: '0 20px 25px -5px rgba(0, 0, 0, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)',
                        position: 'relative', overflow: 'hidden'
                    }} role="dialog" aria-modal="true">

                        <div style={{ padding: '1.5rem', paddingBottom: '1rem' }}>
                            <h2 style={{ fontSize: '1.125rem', fontWeight: 600, margin: 0, lineHeight: 1 }}>Subir Nuevas Tarifas</h2>
                            <p style={{ fontSize: '0.875rem', color: '#6b7280', marginTop: '0.375rem' }}>
                                Sube hojas de tarifas en PDF. La IA intentar├í extraer los precios autom├íticamente.
                            </p>
                        </div>

                        <div style={{ padding: '0 1.5rem 1.5rem 1.5rem' }}>
                            <div className="grid gap-4 py-4">
                                <div
                                    style={{
                                        border: '2px dashed #e5e7eb', borderRadius: '0.5rem', padding: '2rem',
                                        textAlign: 'center', transition: 'background-color 0.2s',
                                        cursor: isUploading ? 'not-allowed' : 'pointer',
                                        opacity: isUploading ? 0.5 : 1,
                                        backgroundColor: '#f9fafb'
                                    }}
                                    onMouseEnter={(e) => { if (!isUploading) e.currentTarget.style.backgroundColor = '#f3f4f6'; }}
                                    onMouseLeave={(e) => { if (!isUploading) e.currentTarget.style.backgroundColor = '#f9fafb'; }}
                                    onClick={() => fileInputRef.current?.click()}
                                >
                                    <input
                                        type="file"
                                        ref={fileInputRef}
                                        style={{ display: 'none' }}
                                        accept="application/pdf"
                                        multiple
                                        onChange={handleFileSelect}
                                    />
                                    <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '0.5rem', color: '#64748b' }}>
                                        <Upload size={32} />
                                        <p style={{ fontSize: '0.875rem', fontWeight: 500, margin: 0 }}>Haz clic para seleccionar PDFs</p>
                                        <p style={{ fontSize: '0.75rem', margin: 0 }}>M├íximo 10MB por archivo</p>
                                    </div>
                                </div>

                                {uploads.length > 0 && (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem', maxHeight: '300px', overflowY: 'auto', paddingRight: '0.5rem' }}>
                                        {uploads.map((upload, index) => (
                                            <div key={index} style={{
                                                display: 'flex', alignItems: 'center', gap: '0.75rem',
                                                backgroundColor: '#f8fafc', padding: '0.75rem', borderRadius: '0.375rem',
                                                border: '1px solid #e2e8f0', fontSize: '0.875rem'
                                            }}>
                                                <FileText size={16} style={{ color: '#3b82f6', flexShrink: 0 }} />
                                                <div style={{ flex: 1, minWidth: 0 }}>
                                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.25rem' }}>
                                                        <span style={{ whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', fontWeight: 500 }}>{upload.file.name}</span>
                                                        <span style={{ fontSize: '0.75rem', color: '#64748b', textTransform: 'capitalize' }}>{upload.status}</span>
                                                    </div>

                                                    {/* Custom Progress Bar */}
                                                    <div style={{ height: '0.375rem', width: '100%', backgroundColor: '#e2e8f0', borderRadius: '9999px', overflow: 'hidden' }}>
                                                        <div style={{
                                                            height: '100%', backgroundColor: '#111827', width: `${upload.progress}%`,
                                                            transition: 'width 0.3s ease'
                                                        }} />
                                                    </div>

                                                    {upload.error && (
                                                        <p style={{ fontSize: '0.75rem', color: '#ef4444', marginTop: '0.25rem' }}>{upload.error}</p>
                                                    )}
                                                </div>
                                                {!isUploading && (
                                                    <button onClick={() => removeFile(index)} style={{ color: '#94a3b8', background: 'none', border: 'none', cursor: 'pointer' }}>
                                                        <X size={16} />
                                                    </button>
                                                )}
                                                {upload.status === 'completed' && <CheckCircle2 size={16} style={{ color: '#22c55e' }} />}
                                                {upload.status === 'error' && <AlertCircle size={16} style={{ color: '#ef4444' }} />}
                                                {(upload.status === 'uploading' || upload.status === 'processing') && <Loader2 size={16} className="animate-spin" style={{ color: '#3b82f6' }} />}
                                            </div>
                                        ))}
                                    </div>
                                )}
                            </div>

                            <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '0.75rem' }}>
                                <button
                                    onClick={() => setIsOpen(false)}
                                    disabled={isUploading}
                                    style={{
                                        display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                                        borderRadius: '0.375rem', fontSize: '0.875rem', fontWeight: 500,
                                        padding: '0.5rem 1rem', backgroundColor: 'white', color: '#1f2937',
                                        border: '1px solid #e5e7eb', cursor: isUploading ? 'not-allowed' : 'pointer'
                                    }}
                                >
                                    Cancelar
                                </button>
                                <button
                                    onClick={startUpload}
                                    disabled={uploads.length === 0 || isUploading}
                                    style={{
                                        display: 'inline-flex', alignItems: 'center', justifyContent: 'center',
                                        borderRadius: '0.375rem', fontSize: '0.875rem', fontWeight: 500,
                                        padding: '0.5rem 1rem', backgroundColor: '#111827', color: 'white',
                                        border: 'none', cursor: (uploads.length === 0 || isUploading) ? 'not-allowed' : 'pointer',
                                        opacity: (uploads.length === 0 || isUploading) ? 0.7 : 1
                                    }}
                                >
                                    {isUploading ? (
                                        <>
                                            <Loader2 size={16} className="animate-spin" style={{ marginRight: '0.5rem' }} />
                                            Procesando...
                                        </>
                                    ) : (
                                        'Iniciar Subida'
                                    )}
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
}

import { useState } from 'react';
import { useToast } from '@/hooks/use-toast';
import { supabase } from '@/shared/lib/supabase';
import { Loader2, Upload } from 'lucide-react';
import { cn } from '@/shared/lib/utils';
import { DetectedTariff } from '@/types/tariff';

interface Step1UploadProps {
    onTariffsDetected: (newCandidates: DetectedTariff[], file: File) => void;
    onManualEntry: () => void;
}

export function Step1Upload({ onTariffsDetected, onManualEntry }: Step1UploadProps) {
    const { toast } = useToast();
    const [processing, setProcessing] = useState(false);

    // PDF Viewer State (Local to upload step for previewing BEFORE parsing?)
    // Actually, user wants preview alongside parsing?
    // In the previous code, preview was always visible.
    // Let's keep it simple: Upload -> Process -> Result.

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        if (processing) return;
        if (e.target.files && e.target.files[0]) {
            const selectedFile = e.target.files[0];
            processFile(selectedFile);
        }
    };

    const processFile = async (f: File) => {
        setProcessing(true);
        try {
            if (!f.type.includes('pdf') && !f.type.includes('image')) {
                toast({ variant: 'destructive', title: 'Error', description: 'Por favor sube un PDF o una Imagen.' });
                setProcessing(false);
                return;
            }

            const { data: { session }, error: sessionError } = await supabase.auth.refreshSession();
            if (sessionError || !session) throw new Error("Sesi├│n expirada.");

            const formData = new FormData();
            formData.append('file', f);

            const { data: extracted, error } = await supabase.functions.invoke('parse-tariff-document', {
                body: formData
            });

            if (error) throw error;
            if (!extracted) throw new Error("No se recibieron datos de la IA");

            const newCandidates: DetectedTariff[] = [];
            const rawTariffs = extracted.tariffs && Array.isArray(extracted.tariffs) ? extracted.tariffs : [extracted];

            rawTariffs.forEach((t: any) => {
                // Normalize contract_duration to number (months)
                let duration: number | null = null;
                if (t.contract_duration != null) {
                    if (typeof t.contract_duration === 'number') {
                        duration = t.contract_duration;
                    } else {
                        // Legacy: parse "12 meses", "1 a├▒o", "24 meses", etc.
                        const str = String(t.contract_duration).toLowerCase().trim();
                        const monthsMatch = str.match(/(\d+)\s*mes/);
                        const yearsMatch = str.match(/(\d+)\s*a[├▒n]o/);
                        if (monthsMatch) duration = parseInt(monthsMatch[1]);
                        else if (yearsMatch) duration = parseInt(yearsMatch[1]) * 12;
                        else {
                            const num = parseInt(str);
                            if (!isNaN(num)) duration = num;
                        }
                    }
                }

                // Build price_sets: use new format or wrap legacy flat arrays
                let priceSets: DetectedTariff['price_sets'] = [];
                if (t.price_sets && Array.isArray(t.price_sets) && t.price_sets.length > 0) {
                    priceSets = t.price_sets.map((ps: any) => {
                        // Parse per-set contract_duration, falling back to the root tariff duration
                        let setDuration: number | null = null;
                        if (ps.contract_duration != null) {
                            setDuration = typeof ps.contract_duration === 'number'
                                ? ps.contract_duration
                                : parseInt(String(ps.contract_duration), 10) || null;
                        } else {
                            setDuration = duration; // Inherit from root tariff
                        }

                        return {
                            contract_duration: setDuration,
                            valid_from: ps.valid_from || undefined,
                            valid_to: ps.valid_to || undefined,
                            energy_prices: ps.energy_prices || [],
                            power_prices: ps.power_prices || [],
                            fixed_term_prices: ps.fixed_term_prices || [],
                        };
                    });
                } else {
                    // Legacy fallback: single price_set from flat arrays
                    priceSets = [{
                        contract_duration: duration,
                        valid_from: t.validity_date || undefined,
                        valid_to: undefined,
                        energy_prices: t.energy_prices || [],
                        power_prices: t.power_prices || [],
                        fixed_term_prices: t.fixed_term_prices || [],
                    }];
                }

                // Build legacy flat arrays from first price_set for UI display compat
                const firstSet = priceSets[0] || { energy_prices: [], power_prices: [], fixed_term_prices: [] };

                newCandidates.push({
                    id: crypto.randomUUID(),
                    fileName: f.name,
                    supplier_name: t.supplier_name,
                    tariff_name: t.tariff_name,
                    tariff_structure: t.tariff_structure,
                    supply_type: t.supply_type || undefined,
                    contract_duration: duration,
                    is_indexed: t.is_indexed,
                    price_sets: priceSets,
                    energy_prices: firstSet.energy_prices,
                    power_prices: firstSet.power_prices,
                    fixed_term_prices: firstSet.fixed_term_prices,
                });
            });

            onTariffsDetected(newCandidates, f);
            toast({ title: "An├ílisis Completado", description: `Se han detectado ${newCandidates.length} tarifa(s).` });

        } catch (err: any) {
            console.error('Error parsing document:', err);
            toast({ variant: 'destructive', title: 'Error', description: err.message || 'Error al analizar el documento.' });
        } finally {
            setProcessing(false);
        }
    };

    return (
        <div className="flex flex-col items-center justify-center min-h-[400px]">
            <div className="w-full max-w-md">
                <div className={cn(
                    "border-2 dashed rounded-lg p-10 text-center transition-colors cursor-pointer",
                    processing ? "border-blue-300 bg-blue-50" : "border-gray-300 hover:bg-gray-50"
                )}>
                    {processing ? (
                        <div className="flex flex-col items-center py-4">
                            <Loader2 size={48} className="animate-spin text-blue-500 mb-4" />
                            <span className="text-lg font-medium text-blue-700">Analizando documento...</span>
                        </div>
                    ) : (
                        <div className="flex flex-col items-center relative">
                            <Upload size={48} className="text-gray-400 mb-4" />
                            <h3 className="text-xl font-medium text-gray-900 mb-2">Subir factura o contrato</h3>
                            <p className="text-gray-500 mb-6">PDF, PNG o JPG hasta 10MB</p>

                            <div className="relative w-full">
                                <button className="btn btn-primary w-full pointer-events-none">
                                    Seleccionar Archivo
                                </button>
                                <input
                                    type="file"
                                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                                    accept=".pdf,image/*"
                                    onChange={handleFileChange}
                                    value=""
                                />
                            </div>
                        </div>
                    )}
                </div>

                <div className="mt-6 text-center">
                    <span className="text-gray-400 text-sm">┬┐Prefieres introducir los datos a mano?</span>
                    <button onClick={onManualEntry} className="text-blue-600 font-medium text-sm ml-2 hover:underline">
                        Entrada Manual
                    </button>
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState, useMemo } from 'react';
import { TariffRate, TariffStructure, TariffWizardState } from '@/types/tariff';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/shared/components/ui/tabs';
import { Plus, Trash2, Clock } from 'lucide-react';
import { ValidityPriceGroup } from './ValidityPriceGroup';

interface Step3AProps {
    data: TariffWizardState;
    structure: TariffStructure | undefined;
    onChange: (rates: TariffRate[]) => void;
    onAddDuration: (months: number) => string | undefined;
    onAddValidityPeriod: (durationKey: string, validFrom: string) => void;
    onDeleteDuration: (durationKey: string) => void;
    onDeleteValidityGroup: (durationKey: string, validFrom: string | null, validTo: string | null) => void;
    onUpdateValidity: (durationKey: string, oldFrom: string | null, oldTo: string | null, newFrom: string | null, newTo: string | null) => void;
}

export function Step3AEnergyPrices({ data, structure, onChange, onAddDuration, onAddValidityPeriod, onDeleteDuration, onDeleteValidityGroup, onUpdateValidity }: Step3AProps) {
    const [activeTab, setActiveTab] = useState<string>("default");
    const [newDuration, setNewDuration] = useState<string>("12");

    const energyRates = useMemo(() => {
        return data.rates.filter(r => r.item_type === 'energy');
    }, [data.rates]);

    // Group by Duration
    const ratesByDuration = useMemo(() => {
        const grouped = new Map<string, TariffRate[]>();
        energyRates.forEach(r => {
            const key = r.contract_duration ? r.contract_duration.toString() : "any";
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return new Map([...grouped.entries()].sort((a, b) => {
            if (a[0] === 'any') return -1;
            if (b[0] === 'any') return 1;
            return parseInt(a[0]) - parseInt(b[0]);
        }));
    }, [energyRates]);

    useEffect(() => {
        const keys = Array.from(ratesByDuration.keys());
        if (keys.length > 0 && !ratesByDuration.has(activeTab) && activeTab !== 'default') {
            setActiveTab(keys[0]);
        } else if (keys.length > 0 && activeTab === 'default') {
            setActiveTab(keys[0]);
        }
    }, [ratesByDuration, activeTab]);

    const handleAddDuration = () => {
        const months = parseInt(newDuration);
        if (isNaN(months) || months <= 0) return;
        onAddDuration(months);
        setActiveTab(months.toString());
    };

    const handleAddValidityPeriod = (durationKey: string) => {
        const today = new Date().toISOString().split('T')[0];
        onAddValidityPeriod(durationKey, today);
    };

    const updateRate = (id: string, field: keyof TariffRate, value: any) => {
        const newRates = data.rates.map(r => r.id === id ? { ...r, [field]: value } : r);
        onChange(newRates);
    };

    const updateValidity = (ids: string[], validFrom: string | null, validTo: string | null) => {
        // Find the duration key and old validity from the first rate in the group
        const firstRate = data.rates.find(r => ids.includes(r.id));
        if (!firstRate) return;
        const durationKey = firstRate.contract_duration ? firstRate.contract_duration.toString() : 'any';
        const oldFrom = firstRate.valid_from || null;
        const oldTo = firstRate.valid_to || null;
        onUpdateValidity(durationKey, oldFrom, oldTo, validFrom, validTo);
    };

    // Group by validity within a duration
    const getRatesByValidity = (rates: TariffRate[]) => {
        const grouped = new Map<string, TariffRate[]>();
        rates.forEach(r => {
            const key = JSON.stringify({ from: r.valid_from || null, to: r.valid_to || null });
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return Array.from(grouped.entries()).sort((a, b) => {
            const dateA = JSON.parse(a[0]).from || '1900-01-01';
            const dateB = JSON.parse(b[0]).from || '1900-01-01';
            return dateA.localeCompare(dateB);
        });
    };

    if (!structure) return <div>Selecciona una estructura en el paso 1.</div>;

    const durationKeys = Array.from(ratesByDuration.keys());

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <div>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 600, color: '#111827', margin: 0 }}>Precios de Energ├¡a</h2>
                <p style={{ fontSize: '0.875rem', color: '#6b7280', margin: '0.25rem 0 0 0' }}>
                    Las duraciones y periodos de vigencia se sincronizan con Precios de Potencia.
                </p>
            </div>

            <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
                <div className="flex items-center gap-2 mb-4 overflow-x-auto pb-2">
                    <TabsList className="bg-slate-100 p-1 rounded-lg">
                        {durationKeys.map(key => (
                            <TabsTrigger key={key} value={key}
                                className="px-4 py-2 rounded-md data-[state=active]:bg-white data-[state=active]:shadow-sm transition-all text-sm font-medium">
                                {key === 'any' ? 'Est├índar (Base)' : `${key} Meses`}
                            </TabsTrigger>
                        ))}
                    </TabsList>

                    <div className="flex items-center gap-2 ml-2">
                        <select
                            className="w-32 px-2 py-1 text-sm border rounded-md"
                            value={newDuration}
                            onChange={(e) => setNewDuration(e.target.value)}
                        >
                            <option value="12">12 Meses</option>
                            <option value="24">24 Meses</option>
                            <option value="36">36 Meses</option>
                        </select>
                        <button type="button" onClick={handleAddDuration}
                            className="p-2 text-primary hover:bg-slate-100 rounded-full transition-colors"
                            title="A├▒adir duraci├│n">
                            <Plus size={18} />
                        </button>
                    </div>
                </div>

                {durationKeys.length === 0 && (
                    <div style={{ padding: '2rem', textAlign: 'center', color: '#6b7280', background: '#f9fafb', borderRadius: '0.5rem' }}>
                        No hay precios configurados. A├▒ade una duraci├│n.
                    </div>
                )}

                {durationKeys.map(key => {
                    const currentDurationRates = ratesByDuration.get(key) || [];
                    const validityGroups = getRatesByValidity(currentDurationRates);

                    return (
                        <TabsContent key={key} value={key} className="space-y-6 animate-in fade-in-50 duration-300">
                            <div className="flex justify-between items-center bg-slate-50 p-3 rounded-lg border border-slate-100 mb-4">
                                <div className="flex items-center gap-2 text-sm text-slate-600">
                                    <Clock size={16} />
                                    <span>Configurando: <strong>{key === 'any' ? 'Cualquier duraci├│n' : `${key} meses`}</strong></span>
                                </div>
                                <button type="button"
                                    onClick={() => { if (confirm('┬┐Eliminar esta duraci├│n de energ├¡a Y potencia?')) onDeleteDuration(key); }}
                                    className="text-red-500 hover:text-red-700 text-xs flex items-center gap-1 px-2 py-1 bg-white border border-red-100 rounded hover:bg-red-50">
                                    <Trash2 size={12} /> Eliminar duraci├│n
                                </button>
                            </div>

                            {validityGroups.map(([validityKey, groupRates]) => (
                                <ValidityPriceGroup
                                    key={validityKey}
                                    rates={groupRates}
                                    onUpdateRate={(id, field, val) => updateRate(id, field, val)}
                                    onUpdateValidity={(f, t) => updateValidity(groupRates.map(r => r.id), f, t)}
                                    onDelete={() => {
                                        const parsed = JSON.parse(validityKey);
                                        onDeleteValidityGroup(key, parsed.from, parsed.to);
                                    }}
                                />
                            ))}

                            <button type="button" onClick={() => handleAddValidityPeriod(key)}
                                style={{
                                    width: '100%', padding: '1rem', border: '2px dashed #e2e8f0',
                                    borderRadius: '0.75rem', color: '#64748b', fontWeight: 500,
                                    cursor: 'pointer', display: 'flex', alignItems: 'center',
                                    justifyContent: 'center', gap: '0.5rem', marginTop: '1rem', background: 'none'
                                }}>
                                <Plus size={20} /> A├▒adir periodo de vigencia (crea energ├¡a + potencia)
                            </button>
                        </TabsContent>
                    );
                })}
            </Tabs>
        </div>
    );
}

import { useEffect, useState, useMemo } from 'react';
import { TariffRate, TariffStructure, TariffWizardState } from '@/types/tariff';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/shared/components/ui/tabs';
import { Plus, Trash2, Clock } from 'lucide-react';
import { ValidityPriceGroup } from './ValidityPriceGroup';

interface Step3BProps {
    data: TariffWizardState;
    structure: TariffStructure | undefined;
    onChange: (rates: TariffRate[]) => void;
    onAddDuration: (months: number) => string | undefined;
    onAddValidityPeriod: (durationKey: string, validFrom: string) => void;
    onDeleteDuration: (durationKey: string) => void;
    onDeleteValidityGroup: (durationKey: string, validFrom: string | null, validTo: string | null) => void;
    onUpdateValidity: (durationKey: string, oldFrom: string | null, oldTo: string | null, newFrom: string | null, newTo: string | null) => void;
}

export function Step3BPowerPrices({ data, structure, onChange, onAddDuration, onAddValidityPeriod, onDeleteDuration, onDeleteValidityGroup, onUpdateValidity }: Step3BProps) {
    const [activeTab, setActiveTab] = useState<string>("default");
    const [newDuration, setNewDuration] = useState<string>("12");

    const powerRates = useMemo(() => {
        return data.rates.filter(r => r.item_type === 'power');
    }, [data.rates]);

    // Group by Duration
    const ratesByDuration = useMemo(() => {
        const grouped = new Map<string, TariffRate[]>();
        powerRates.forEach(r => {
            const key = r.contract_duration ? r.contract_duration.toString() : "any";
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return new Map([...grouped.entries()].sort((a, b) => {
            if (a[0] === 'any') return -1;
            if (b[0] === 'any') return 1;
            return parseInt(a[0]) - parseInt(b[0]);
        }));
    }, [powerRates]);

    useEffect(() => {
        const keys = Array.from(ratesByDuration.keys());
        if (keys.length > 0 && !ratesByDuration.has(activeTab) && activeTab !== 'default') {
            setActiveTab(keys[0]);
        } else if (keys.length > 0 && activeTab === 'default') {
            setActiveTab(keys[0]);
        }
    }, [ratesByDuration, activeTab]);

    const handleAddDuration = () => {
        const months = parseInt(newDuration);
        if (isNaN(months) || months <= 0) return;
        onAddDuration(months);
        setActiveTab(months.toString());
    };

    const handleAddValidityPeriod = (durationKey: string) => {
        const today = new Date().toISOString().split('T')[0];
        onAddValidityPeriod(durationKey, today);
    };

    const updateRate = (id: string, field: keyof TariffRate, value: any) => {
        const newRates = data.rates.map(r => {
            if (r.id === id) {
                if (field === 'price' && typeof value === 'number') return { ...r, price: value };
                if (field === 'unit' && typeof value === 'string') return { ...r, unit: value };
                return { ...r, [field]: value };
            }
            return r;
        });
        onChange(newRates);
    };

    const updateValidity = (ids: string[], validFrom: string | null, validTo: string | null) => {
        const firstRate = data.rates.find(r => ids.includes(r.id));
        if (!firstRate) return;
        const durationKey = firstRate.contract_duration ? firstRate.contract_duration.toString() : 'any';
        const oldFrom = firstRate.valid_from || null;
        const oldTo = firstRate.valid_to || null;
        onUpdateValidity(durationKey, oldFrom, oldTo, validFrom, validTo);
    };

    const getRatesByValidity = (rates: TariffRate[]) => {
        const grouped = new Map<string, TariffRate[]>();
        rates.forEach(r => {
            const key = JSON.stringify({ from: r.valid_from || null, to: r.valid_to || null });
            if (!grouped.has(key)) grouped.set(key, []);
            grouped.get(key)!.push(r);
        });
        return Array.from(grouped.entries()).sort((a, b) => {
            const dateA = JSON.parse(a[0]).from || '1900-01-01';
            const dateB = JSON.parse(b[0]).from || '1900-01-01';
            return dateA.localeCompare(dateB);
        });
