                            }}
                        />
                    </div>
                </div>
                <p style={{ fontSize: '0.75rem', color: '#166534', marginTop: '0.5rem', opacity: 0.8 }}>
                    Este precio se aplica a los excesos registrados por el max├¡metro o telemedida.
                </p>
            </div>
        </div>
    );
}

import { TariffRate, TariffWizardState } from '@/types/tariff';
import { Plus, Trash2 } from 'lucide-react';

interface Step5Props {
    data: TariffWizardState;
    onChange: (rates: TariffRate[]) => void;
}

export function Step5FeesAndTaxes({ data, onChange }: Step5Props) {
    const feesAndTaxes = data.rates.filter(r => ['fixed_fee', 'tax', 'discount'].includes(r.item_type));

    const addRate = (type: 'fixed_fee' | 'tax' | 'discount') => {
        const newRate: TariffRate = {
            id: crypto.randomUUID(),
            tariff_version_id: '',
            item_type: type,
            price: 0,
            unit: type === 'fixed_fee' ? 'EUR/month' : '%',
        };
        onChange([...data.rates, newRate]);
    };

    const removeRate = (id: string) => {
        onChange(data.rates.filter(r => r.id !== id));
    };

    const updateRate = <K extends keyof TariffRate>(id: string, field: K, value: TariffRate[K]) => {
        const updatedRates = data.rates.map(r => r.id === id ? { ...r, [field]: value } : r);
        onChange(updatedRates);
    };

    const labelStyle = { display: 'block', fontSize: '0.75rem', fontWeight: 500, color: '#374151', marginBottom: '0.25rem' };
    const inputStyle = {
        width: '100%',
        padding: '0.375rem 0.5rem',
        borderRadius: '0.375rem',
        border: '1px solid #d1d5db',
        fontSize: '0.875rem',
        outline: 'none'
    };

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 600, color: '#111827', margin: 0 }}>Cargos Extra e Impuestos</h2>

            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                {feesAndTaxes.map((rate) => (
                    <div key={rate.id} className="card" style={{ padding: '1rem', display: 'flex', gap: '1rem', alignItems: 'flex-end', background: 'white', border: '1px solid #e5e7eb', borderRadius: '0.5rem' }}>
                        <div style={{ flex: 1 }}>
                            <label style={labelStyle}>Tipo</label>
                            <select
                                style={inputStyle}
                                value={rate.item_type}
                                onChange={(e) => updateRate(rate.id, 'item_type', e.target.value as any)}
                            >
                                <option value="fixed_fee">Cuota Fija</option>
                                <option value="tax">Impuesto</option>
                                <option value="discount">Descuento</option>
                            </select>
                        </div>
                        <div style={{ flex: 1 }}>
                            <label style={labelStyle}>Valor</label>
                            <input
                                type="number"
                                style={inputStyle}
                                value={rate.price || ''}
                                onChange={(e) => updateRate(rate.id, 'price', parseFloat(e.target.value))}
                            />
                        </div>
                        <div style={{ width: '6rem' }}>
                            <label style={labelStyle}>Unidad</label>
                            <select
                                style={inputStyle}
                                value={rate.unit}
                                onChange={(e) => updateRate(rate.id, 'unit', e.target.value)}
                            >
                                <option value="EUR/month">Ôé¼/mes</option>
                                <option value="EUR/day">Ôé¼/d├¡a</option>
                                <option value="%">%</option>
                            </select>
                        </div>
                        <button
                            onClick={() => removeRate(rate.id)}
                            style={{
                                border: 'none',
                                background: 'transparent',
                                color: '#ef4444',
                                cursor: 'pointer',
                                padding: '0.5rem',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                ))}

                {feesAndTaxes.length === 0 && (
                    <p style={{ color: '#6b7280', fontSize: '0.875rem', fontStyle: 'italic', margin: 0 }}>No hay cargos extra configurados.</p>
                )}
            </div>

            <div style={{ display: 'flex', gap: '0.5rem' }}>
                <button onClick={() => addRate('fixed_fee')} className="btn btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Plus size={16} /> A├▒adir Cuota
                </button>
                <button onClick={() => addRate('tax')} className="btn btn-secondary" style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <Plus size={16} /> A├▒adir Impuesto
                </button>
            </div>
        </div>
    );
}

import { TariffWizardState } from '@/types/tariff';
import { CheckCircle2, AlertTriangle, Loader2 } from 'lucide-react';
import { supabase } from '@/shared/lib/supabase';
import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useToast } from '@/hooks/use-toast';
import { ConfirmDialog } from '@/shared/components/ConfirmDialog';

interface Step6Props {
    data: TariffWizardState;
    mode?: 'create' | 'edit';
    onSave: () => void;
}

export function Step6Summary({ data, mode = 'create' }: Step6Props) {
    const navigate = useNavigate();
    const [saving, setSaving] = useState(false);
    const { toast } = useToast();
    const { id } = useParams();
    const [showDeleteDialog, setShowDeleteDialog] = useState(false);

    // Validation status
    const hasRates = data.rates && data.rates.length > 0;
    const isComplete = data.metadata.supplier_id && data.metadata.name && data.metadata.tariff_structure_id && hasRates;

    const handleDelete = async () => {
        if (!id) return;

        setSaving(true);
        try {
            const { error } = await supabase.from('tariff_versions').delete().eq('id', id);
            if (error) throw error;
            toast({ title: 'Tarifa eliminada', description: 'La tarifa ha sido eliminada correctamente.' });
            navigate('/admin/tariffs');
        } catch (error: any) {
            console.error(error);
            toast({ variant: 'destructive', title: 'Error', description: 'No se pudo eliminar la tarifa.' });
        } finally {
            setSaving(false);
            setShowDeleteDialog(false);
        }
    };

    const handleSave = async (activate: boolean) => {
        setSaving(true);
        try {
            // 1. Prepare Payload
            const { data: user } = await supabase.auth.getUser();
            const { data: company } = await supabase.from('users').select('company_id').eq('id', user.user!.id).single();

            const { data: selectedStructure } = await supabase
                .from('tariff_structures')
                .select('code')
                .eq('id', data.metadata.tariff_structure_id)
                .single();

            const payload = {
                company_id: company?.company_id,
                supplier_id: data.metadata.supplier_id,
                tariff_structure_id: data.metadata.tariff_structure_id,
                tariff_name: data.metadata.name,
                tariff_code: data.metadata.code,
                tariff_type: selectedStructure?.code || '2.0TD',
                is_indexed: data.metadata.is_indexed,
                valid_from: data.metadata.valid_from,
                is_active: activate,
                completion_status: isComplete ? 'complete' : 'draft'
            };

            let versionId = id;

            if (mode === 'create' || id) {
                // Use upsert to handle retries and updates uniformly
                const { data: version, error: vError } = await supabase
                    .from('tariff_versions')
                    .upsert(payload, {
                        onConflict: 'company_id, supplier_id, tariff_name, valid_from'
                    })
                    .select()
                    .single();

                if (vError) throw vError;
                versionId = version.id;
            }

            if (!versionId) throw new Error("No version ID");

            // 2. Handle Rates 
            // Always delete existing rates for this version before inserting new ones to ensure clean state
            await supabase.from('tariff_rates').delete().eq('tariff_version_id', versionId);

            const ratesPayload = data.rates.map(r => ({
                id: crypto.randomUUID(), // Always new IDs for rates
                tariff_version_id: versionId,
                item_type: r.item_type,
                period: r.period,
                price: r.price,
                price_formula: r.price_formula,
                unit: r.unit,
                confidence_score: r.confidence_score,
                contract_duration: r.contract_duration ?? null,
                valid_from: r.valid_from ?? data.metadata.valid_from ?? null,
                valid_to: r.valid_to ?? null
            }));

            if (ratesPayload.length > 0) {
                const { error: rError } = await supabase
                    .from('tariff_rates')
                    .insert(ratesPayload);
                if (rError) throw rError;
            }

            // 3. Insert Schedules
            // Always delete existing schedules for this version before inserting new ones
            await supabase.from('tariff_schedules').delete().eq('tariff_version_id', versionId);

            const schedulesPayload = data.schedules.map(s => ({
                id: crypto.randomUUID(), // Always new IDs for schedules
                tariff_version_id: versionId,
                month_mask: s.month_mask,
                day_type_mask: s.day_type_mask,
                start_hour: s.start_hour.includes(':') && s.start_hour.split(':').length === 2 ? `${s.start_hour}:00` : s.start_hour,
                end_hour: s.end_hour.includes(':') && s.end_hour.split(':').length === 2 ? `${s.end_hour}:59` : s.end_hour,
                period: s.period,
                context_calendar: s.context_calendar
            }));

            if (schedulesPayload.length > 0) {
                const { error: sError } = await supabase
                    .from('tariff_schedules')
                    .insert(schedulesPayload);
                if (sError) throw sError;
            }

            toast({
                title: mode === 'create' ? "Tarifa Creada" : "Tarifa Actualizada",
                description: `La tarifa ${data.metadata.name} ha sido guardada correctamente.`,
            });

            navigate('/admin/tariffs');

        } catch (err: any) {
            console.error(err);
            toast({
                variant: 'destructive',
                title: "Error al guardar",
                description: err.message,
            });
        } finally {
            setSaving(false);
        }
    };

    if (!data) return null;

    return (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 600, color: '#111827', margin: 0 }}>Resumen y Confirmaci├│n</h2>

            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '1.5rem' }}>
                <div className="card" style={{ padding: '1.5rem' }}>
                    <h3 style={{ fontWeight: 500, marginBottom: '1rem', color: '#111827', margin: '0 0 1rem 0' }}>Datos Generales</h3>
                    <dl style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', fontSize: '0.875rem', margin: 0 }}>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <dt style={{ color: '#6b7280' }}>Nombre:</dt>
                            <dd style={{ fontWeight: 500 }}>{data.metadata.name}</dd>
                        </div>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <dt style={{ color: '#6b7280' }}>Modalidad:</dt>
                            <dd style={{ fontWeight: 500 }}>{data.metadata.is_indexed ? 'Indexado' : 'Fijo'}</dd>
                        </div>
                        <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                            <dt style={{ color: '#6b7280' }}>Vigencia:</dt>
                            <dd style={{ fontWeight: 500 }}>{data.metadata.valid_from}</dd>
                        </div>
                    </dl>
                </div>

                <div className="card" style={{ padding: '1.5rem' }}>
                    <h3 style={{ fontWeight: 500, marginBottom: '1rem', color: '#111827', margin: '0 0 1rem 0' }}>Estado de Validaci├│n</h3>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.5rem' }}>
                        {isComplete ? (
                            <CheckCircle2 size={20} style={{ color: '#22c55e' }} />
                        ) : (
                            <AlertTriangle size={20} style={{ color: '#eab308' }} />
                        )}
                        <span style={{ fontWeight: 500 }}>
                            {isComplete ? 'Completa' : 'Faltan datos obligatorios (Metadata o Precios)'}
                        </span>
                    </div>
                    <p style={{ fontSize: '0.75rem', color: '#6b7280', margin: 0 }}>
                        {isComplete
                            ? "La tarifa est├í lista para ser activada y utilizada en recomendaciones."
                            : "Puedes guardar como borrador y terminar de editar m├ís tarde."}
                    </p>
                </div>
            </div>

            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', paddingTop: '1.5rem', borderTop: '1px solid #e5e7eb' }}>
                {mode === 'edit' && (
                    <button
                        onClick={() => setShowDeleteDialog(true)}
                        disabled={saving}
                        className="btn btn-secondary"
                        style={{ color: '#ef4444', borderColor: '#fca5a5', background: '#fef2f2' }}
                    >
                        {saving ? <Loader2 size={16} className="animate-spin" /> : 'Eliminar Tarifa'}
                    </button>
                )}

                <div style={{ display: 'flex', gap: '0.75rem', marginLeft: 'auto' }}>
                    <button
                        className="btn btn-secondary"
                        onClick={() => handleSave(false)}
                        disabled={saving}
                    >
                        {saving ? <Loader2 size={16} className="animate-spin" /> : 'Guardar Borrador'}
                    </button>
                    <button
                        className="btn btn-primary"
                        onClick={() => handleSave(true)}
                        disabled={saving || !isComplete}
                    >
                        {saving ? <Loader2 size={16} className="animate-spin" /> : mode === 'edit' ? 'Actualizar Tarifa' : 'Publicar y Activar'}
                    </button>
                </div>
            </div>

            <ConfirmDialog
                isOpen={showDeleteDialog}
                title="Eliminar tarifa"
                message="┬┐Est├ís seguro de que quieres eliminar esta tarifa? Esta acci├│n no se puede deshacer."
                confirmLabel="Eliminar"
                variant="danger"
                onConfirm={handleDelete}
                onCancel={() => setShowDeleteDialog(false)}
            />
        </div>
    );
}

import { useParams, useNavigate } from 'react-router-dom';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/shared/lib/supabase';
import { Loader2, ArrowLeft, FileText, CheckCircle, AlertCircle, Clock } from 'lucide-react';


interface TariffFile {
    id: string;
    filename: string;
    status: string; // 'pending' | 'processing' | 'completed' | 'failed'
    file_size_bytes: number;
    created_at: string;
}

interface TariffBatch {
    id: string;
    status: string;
    file_count: number;
    created_at: string;
    files: TariffFile[];
}

export default function BatchDetailsPage() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();

    const { data: batch, isLoading, error } = useQuery({
        queryKey: ['tariff-batch', id],
        queryFn: async () => {
            if (!id) throw new Error('No batch ID');

            // Fetch batch details
            const { data: batchData, error: batchError } = await supabase
                .from('tariff_batches')
                .select('*')
                .eq('id', id)
                .single();

            if (batchError) throw batchError;

            // Fetch files in batch
            const { data: filesData, error: filesError } = await supabase
                .from('tariff_files')
                .select('*')
                .eq('batch_id', id);

            if (filesError) throw filesError;

            return {
                ...batchData,
                files: filesData || []
            } as TariffBatch;
        },
        enabled: !!id,
        refetchInterval: (query) => {
            const data = query.state.data;
            // Poll if status is processing or uploaded
            if (data?.status === 'processing' || data?.status === 'uploaded') {
                return 2000;
            }
            return false;
        }
    });

    if (isLoading) {
        return (
            <div className="flex justify-center items-center h-96">
                <Loader2 size={32} className="animate-spin" style={{ color: '#3b82f6' }} />
            </div>
        );
    }

    if (error || !batch) {
        return (
            <div className="container mx-auto py-8 text-center text-red-500">
                <div style={{ fontSize: '1.25rem', fontWeight: 700, marginBottom: '0.5rem' }}>Error cargando el lote</div>
                <p style={{ marginBottom: '1rem' }}>{(error as any)?.message || 'Lote no encontrado'}</p>
                <button
                    onClick={() => navigate('/admin/tariffs')}
                    style={{
                        background: 'transparent', border: 'none', cursor: 'pointer',
                        color: '#4b5563', fontSize: '0.875rem', textDecoration: 'underline'
                    }}
                >
                    Volver
                </button>
            </div>
        );
    }



    const getStatusIcon = (status: string) => {
        switch (status) {
            case 'completed': return <CheckCircle className="w-4 h-4" />;
            case 'processing': return <Loader2 className="w-4 h-4 animate-spin" />;
            case 'failed': return <AlertCircle className="w-4 h-4" />;
            default: return <Clock className="w-4 h-4" />;
        }
    };

    return (
        <div style={{ maxWidth: '64rem', margin: '0 auto', padding: '2rem 1rem', animation: 'fadeIn 0.5s ease-out' }}>
            <div style={{ marginBottom: '1.5rem' }}>
                <button
                    onClick={() => navigate('/admin/tariffs')}
                    style={{
                        marginBottom: '1rem', paddingLeft: 0, background: 'transparent',
                        border: 'none', cursor: 'pointer', display: 'flex', alignItems: 'center',
                        color: '#4b5563', fontSize: '0.875rem'
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.paddingLeft = '0.5rem'}
                    onMouseLeave={(e) => e.currentTarget.style.paddingLeft = '0'}
                >
                    <ArrowLeft size={16} style={{ marginRight: '0.5rem' }} />
                    Volver al Dashboard
                </button>

                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                    <div>
                        <div style={{ fontSize: '1.5rem', fontWeight: 700, display: 'flex', alignItems: 'center', gap: '0.75rem', margin: 0 }}>
                            Lote de Tarifas
                            <span style={{
                                padding: '0.125rem 0.625rem', borderRadius: '9999px', fontSize: '0.75rem', fontWeight: 500,
                                border: '1px solid transparent', textTransform: 'uppercase',
                                backgroundColor: batch.status === 'completed' ? '#dcfce7' : batch.status === 'failed' ? '#fee2e2' : '#f3f4f6',
                                color: batch.status === 'completed' ? '#166534' : batch.status === 'failed' ? '#991b1b' : '#1f2937',
                                borderColor: batch.status === 'completed' ? '#bbf7d0' : batch.status === 'failed' ? '#fecaca' : '#e5e7eb'
                            }}>
                                {batch.status.toUpperCase()}
                            </span>
                        </div>
                        <p style={{ color: '#6b7280', marginTop: '0.25rem', margin: 0 }}>ID: {batch.id}</p>
                        <p style={{ color: '#6b7280', fontSize: '0.875rem', margin: 0 }}>Fecha: {new Date(batch.created_at).toLocaleString()}</p>
                    </div>
                </div>
            </div>

            <div style={{ backgroundColor: 'white', border: '1px solid #e5e7eb', borderRadius: '0.5rem', boxShadow: '0 1px 2px 0 rgba(0, 0, 0, 0.05)', overflow: 'hidden' }}>
                <div style={{ padding: '1rem', borderBottom: '1px solid #e5e7eb', backgroundColor: '#f9fafb', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>

                </div>

                <div>
                    {batch.files.length === 0 ? (
                        <div style={{ padding: '2rem', textAlign: 'center', color: '#9ca3af' }}>
                            No hay archivos en este lote.
                        </div>
                    ) : (
                        batch.files.map((file, idx) => (
                            <div
                                key={file.id}
                                style={{
                                    padding: '1rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                                    backgroundColor: 'white',
                                    borderBottom: idx < batch.files.length - 1 ? '1px solid #f3f4f6' : 'none',
                                    transition: 'background-color 0.2s'
                                }}
                                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = '#f9fafb'}
                                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = 'white'}
                            >
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                    <div style={{ padding: '0.5rem', backgroundColor: '#eff6ff', borderRadius: '0.25rem', color: '#3b82f6' }}>
                                        <FileText size={20} />
                                    </div>
                                    <div>
                                        <p style={{ fontWeight: 500, fontSize: '0.875rem', margin: 0 }}>{file.filename}</p>
                                        <p style={{ fontSize: '0.75rem', color: '#6b7280', margin: 0 }}>{(file.file_size_bytes / 1024).toFixed(1)} KB</p>
                                    </div>
                                </div>

                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <div style={{
                                        display: 'flex', alignItems: 'center', gap: '0.5rem', padding: '0.25rem 0.75rem',
                                        borderRadius: '9999px', fontSize: '0.75rem', fontWeight: 500,
                                        backgroundColor: file.status === 'completed' ? '#dcfce7' : file.status === 'failed' ? '#fee2e2' : '#f3f4f6',
                                        color: file.status === 'completed' ? '#166534' : file.status === 'failed' ? '#991b1b' : '#1f2937',
                                    }}>
                                        {getStatusIcon(file.status || 'pending')}
                                        <span style={{ textTransform: 'capitalize' }}>{file.status || 'pending'}</span>
                                    </div>
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>
        </div>
    );
}

import { useEffect, useState } from 'react'
import { Bell } from 'lucide-react'
import { supabase } from '@/shared/lib/supabase'
import { useNavigate } from 'react-router-dom'

interface Notification {
    id: string
    type: string
    title: string
    message: string
    link: string | null
    read: boolean
    created_at: string
    metadata: any
}

export function NotificationBell() {
    const [notifications, setNotifications] = useState<Notification[]>([])
    const [unreadCount, setUnreadCount] = useState(0)
    const [showDropdown, setShowDropdown] = useState(false)
    const navigate = useNavigate()

    useEffect(() => {
        fetchNotifications()

        // Suscripci├│n a cambios en tiempo real
        const channel = supabase
            .channel('notifications')
            .on(
                'postgres_changes',
                { event: 'INSERT', schema: 'public', table: 'notifications', filter: `user_id=eq.${supabase.auth.getUser().then(u => u.data.user?.id)}` },
                () => fetchNotifications()
            )
            .subscribe()

        return () => {
            supabase.removeChannel(channel)
        }
    }, [])

    const fetchNotifications = async () => {
        try {
            const { data, error } = await supabase
                .from('notifications')
                .select('*')
                .order('created_at', { ascending: false })
                .limit(10)

            if (data && !error) {
                setNotifications(data)
                setUnreadCount(data.filter(n => !n.read).length)
            }
        } catch (err) {
            // Silently fail if notifications table doesn't exist yet
            console.warn('Notifications table not available')
        }
    }

    const markAsRead = async (id: string) => {
        await supabase
            .from('notifications')
            .update({ read: true })
            .eq('id', id)

        fetchNotifications()
    }

    const markAllAsRead = async () => {
        const { data: { user } } = await supabase.auth.getUser()
        if (!user) return

        await supabase
            .from('notifications')
            .update({ read: true })
            .eq('user_id', user.id)
            .eq('read', false)

        fetchNotifications()
    }

    const handleNotificationClick = (notification: Notification) => {
        markAsRead(notification.id)
        if (notification.link) {
            navigate(notification.link)
            setShowDropdown(false)
        }
    }

    // Cerrar dropdown al hacer click fuera
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            const target = event.target as HTMLElement
            if (!target.closest('.notification-bell-container')) {
                setShowDropdown(false)
            }
        }

        if (showDropdown) {
            document.addEventListener('click', handleClickOutside)
        }

        return () => {
            document.removeEventListener('click', handleClickOutside)
        }
    }, [showDropdown])

    return (
        <div className="notification-bell-container" style={{ position: 'relative' }}>
            <button
                onClick={() => setShowDropdown(!showDropdown)}
                style={{
                    position: 'relative',
                    padding: '0.5rem',
                    background: 'transparent',
                    border: 'none',
                    cursor: 'pointer',
                    borderRadius: '6px',
                    transition: 'background 0.2s'
                }}
                onMouseEnter={(e) => e.currentTarget.style.background = '#f1f3f5'}
                onMouseLeave={(e) => e.currentTarget.style.background = 'transparent'}
                title="Notificaciones"
            >
                <Bell size={20} />
                {unreadCount > 0 && (
                    <span style={{
                        position: 'absolute',
                        top: '4px',
                        right: '4px',
                        background: '#ff4444',
                        color: 'white',
                        borderRadius: '50%',
                        width: '18px',
                        height: '18px',
                        fontSize: '0.7rem',
                        fontWeight: 'bold',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        border: '2px solid white'
                    }}>
                        {unreadCount > 9 ? '9+' : unreadCount}
                    </span>
                )}
            </button>

            {showDropdown && (
                <div style={{
                    position: 'absolute',
                    top: 'calc(100% + 8px)',
                    right: '0',
                    width: '400px',
                    maxHeight: '500px',
                    background: 'white',
                    border: '1px solid var(--border)',
                    borderRadius: '12px',
                    boxShadow: '0 8px 24px rgba(0,0,0,0.12)',
                    marginTop: '0.5rem',
                    zIndex: 1000,
                    overflow: 'hidden'
                }}>
                    <div style={{
                        padding: '1rem 1.25rem',
                        borderBottom: '1px solid var(--border)',
                        display: 'flex',
                        justifyContent: 'space-between',
                        alignItems: 'center',
                        background: '#fafafa'
                    }}>
                        <h3 style={{ margin: 0, fontSize: '1rem', fontWeight: 600 }}>
                            Notificaciones
                        </h3>
                        {unreadCount > 0 && (
                            <button
                                onClick={markAllAsRead}
                                style={{
                                    background: 'none',
                                    border: 'none',
                                    color: 'var(--primary)',
                                    fontSize: '0.875rem',
                                    cursor: 'pointer',
                                    padding: '0.25rem 0.5rem',
                                    fontWeight: 500
                                }}
                            >
                                Marcar todas como le├¡das
                            </button>
                        )}
                    </div>

                    <div style={{ maxHeight: '440px', overflowY: 'auto' }}>
                        {notifications.length === 0 ? (
                            <div style={{ padding: '3rem 2rem', textAlign: 'center', color: 'var(--text-muted)' }}>
                                <Bell size={48} style={{ opacity: 0.3, marginBottom: '1rem' }} />
                                <p style={{ margin: 0 }}>No hay notificaciones</p>
                            </div>
                        ) : (
                            notifications.map((notif) => (
                                <div
                                    key={notif.id}
                                    onClick={() => handleNotificationClick(notif)}
                                    style={{
                                        padding: '1rem 1.25rem',
                                        borderBottom: '1px solid var(--border-light)',
                                        cursor: notif.link ? 'pointer' : 'default',
                                        background: notif.read ? 'white' : '#f0f7ff',
                                        transition: 'background 0.2s',
                                        position: 'relative'
                                    }}
                                    onMouseEnter={(e) => {
                                        if (notif.link) {
                                            e.currentTarget.style.background = notif.read ? '#f8f9fa' : '#e3f2ff'
                                        }
                                    }}
                                    onMouseLeave={(e) => {
                                        e.currentTarget.style.background = notif.read ? 'white' : '#f0f7ff'
                                    }}
                                >
                                    {!notif.read && (
                                        <div style={{
                                            position: 'absolute',
                                            left: '0.5rem',
                                            top: '50%',
                                            transform: 'translateY(-50%)',
                                            width: '8px',
                                            height: '8px',
                                            borderRadius: '50%',
                                            background: 'var(--primary)'
                                        }} />
                                    )}
                                    <div style={{
                                        fontWeight: notif.read ? 'normal' : '600',
                                        marginBottom: '0.25rem',
                                        fontSize: '0.9375rem',
                                        paddingLeft: notif.read ? '0' : '1rem'
                                    }}>
                                        {notif.title}
                                    </div>
                                    <div style={{
                                        fontSize: '0.875rem',
                                        color: 'var(--text-muted)',
                                        lineHeight: '1.4',
                                        paddingLeft: notif.read ? '0' : '1rem'
                                    }}>
                                        {notif.message}
                                    </div>
                                    <div style={{
                                        fontSize: '0.75rem',
                                        color: 'var(--text-muted)',
                                        marginTop: '0.5rem',
                                        paddingLeft: notif.read ? '0' : '1rem'
                                    }}>
                                        {new Date(notif.created_at).toLocaleString('es-ES', {
                                            day: 'numeric',
                                            month: 'short',
                                            hour: '2-digit',
                                            minute: '2-digit'
                                        })}
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            )}
        </div>
    )
}

